   820 |     // In order to check that `%a != %b` is true (non-equality), either
   821 |     // condition `%a > %b` or `%a < %b` must hold true. When checking for
   822 |     // non-equality (`IsNe` is true), we return true if one of the two holds,
   823 |     // false in the other cases.
   824 |     if (IsNegatedImplied || IsStrictLessThanImplied)
