   648 |     if (match(Op1, m_Zero())) {
   649 |       Pred = CmpInst::ICMP_ULE;
   650 |     } else {
   651 |       IsEq = true;
   652 |       Pred = CmpInst::ICMP_ULE;
   653 |     }
   654 |     break;
   655 |   case CmpInst::ICMP_NE:
